// --- Data Models ---

sealed class PaymentResult {
    data class Success(val transactionId: String, val message: String = "") : PaymentResult()
    data class Failure(val errorCode: Int, val errorMessage: String) : PaymentResult()
    object Pending : PaymentResult()
    object UserCancelled : PaymentResult()
    data class BillingUnavailable(val message: String) : PaymentResult()
}

data class ProductInfo(
    val productId: String,
    val type: String, // e.g., BillingClient.ProductType.INAPP, BillingClient.ProductType.SUBS
    val title: String,
    val description: String,
    val price: String, // Formatted price, e.g., "$1.99"
    val originalProductDetails: ProductDetails // Original object for purchase flow
)

data class WalletTransaction(
    val amount: Double,
    val currency: String,
    val description: String,
    val paymentMethodToken: String? = null // Token from external payment gateway (e.g., Stripe, PayPal)
)

// --- Constants (Example Product IDs) ---

object PaymentConstants {
    const val PRODUCT_ID_COINS_100 = "com.example.app.coins_100"
    const val PRODUCT_ID_PREMIUM_SUBSCRIPTION = "com.example.app.premium_subscription"
    const val WALLET_TOPUP_PRODUCT_ID = "com.example.app.wallet_topup" // Example IAP to fund wallet
}

