// --- Google Play Billing Manager ---

class GooglePlayBillingManager(
    private val context: Context,
    private val defaultScope: CoroutineScope
) : PurchasesUpdatedListener, BillingClientStateListener {

    private lateinit var billingClient: BillingClient

    private val _connectionState = MutableStateFlow(BillingClient.ConnectionState.DISCONNECTED)
    val connectionState: StateFlow<Int> = _connectionState.asStateFlow()

    private val _purchasesFlow = MutableStateFlow<List<Purchase>>(emptyList())
    val purchasesFlow: StateFlow<List<Purchase>> = _purchasesFlow.asStateFlow()

    private val _productDetailsFlow = MutableStateFlow<Map<String, ProductInfo>>(emptyMap())
    val productDetailsFlow: StateFlow<Map<String, ProductInfo>> = _productDetailsFlow.asStateFlow()

    private val _purchaseResultFlow = MutableStateFlow<PaymentResult?>(null)
    val purchaseResultFlow: StateFlow<PaymentResult?> = _purchaseResultFlow.asStateFlow()

    private val productList = listOf(
        QueryProductDetailsParams.Product.newBuilder()
            .setProductId(PaymentConstants.PRODUCT_ID_COINS_100)
            .setProductType(BillingClient.ProductType.INAPP)
            .build(),
        QueryProductDetailsParams.Product.newBuilder()
            .setProductId(PaymentConstants.PRODUCT_ID_PREMIUM_SUBSCRIPTION)
            .setProductType(BillingClient.ProductType.SUBS)
            .build(),
        QueryProductDetailsParams.Product.newBuilder()
            .setProductId(PaymentConstants.WALLET_TOPUP_PRODUCT_ID)
            .setProductType(BillingClient.ProductType.INAPP)
            .build()
    )

    init {
        setupBillingClient()
    }

    private fun setupBillingClient() {
        billingClient = BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()
        connectToGooglePlay()
    }

    fun connectToGooglePlay() {
        if (!billingClient.isReady) {
            billingClient.startConnection(this)
        }
    }

    override fun onBillingSetupFinished(billingResult: BillingResult) {
        _connectionState.value = billingClient.connectionState
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
            defaultScope.launch {
                queryProductDetails()
                queryPurchases()
            }
        } else {
            _purchaseResultFlow.value = PaymentResult.BillingUnavailable(
                "Billing setup failed: ${billingResult.debugMessage}"
            )
        }
    }

    override fun onBillingServiceDisconnected() {
        _connectionState.value = billingClient.connectionState
        // Try to restart the connection on the next request to Google Play by calling the startConnection() method.
        // Or, you can implement a retry logic here with a delay.
        // connectToGooglePlay() // Example of immediate retry, consider exponential backoff
    }

    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: MutableList<Purchase>?) {
        when (billingResult.responseCode) {
            BillingClient.BillingResponseCode.OK -> {
                purchases?.let { handlePurchases(it) }
            }
            BillingClient.BillingResponseCode.USER_CANCELED -> {
                _purchaseResultFlow.value = PaymentResult.UserCancelled
            }
            BillingClient.BillingResponseCode.ITEM_ALREADY_OWNED -> {
                _purchaseResultFlow.value = PaymentResult.Failure(
                    billingResult.responseCode,
                    "You already own this item."
                )
                purchases?.let { handlePurchases(it) } // Still process to acknowledge if needed
            }
            else -> {
                _purchaseResultFlow.value = PaymentResult.Failure(
                    billingResult.responseCode,
                    "Purchase failed: ${billingResult.debugMessage}"
                )
            }
        }
    }

    private fun handlePurchases(purchases: List<Purchase>) {
        defaultScope.launch {
            val validPurchases = mutableListOf<Purchase>()
            for (purchase in purchases) {
                if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
                    // IMPORTANT: VERIFY PURCHASE ON YOUR SECURE BACKEND SERVER
                    // Send purchase.purchaseToken, purchase.orderId to your backend for verification.
                    // DO NOT rely solely on client-side verification.
                    val isPurchaseVerified = withContext(Dispatchers.IO) {
                        // Simulate backend verification
                        kotlinx.coroutines.delay(500)
                        true // In a real app, this would be a backend call
                    }

                    if (isPurchaseVerified) {
                        if (!purchase.isAcknowledged) {
                            acknowledgePurchase(purchase)
                        }
                        validPurchases.add(purchase)
                        _purchaseResultFlow.value = PaymentResult.Success(
                            purchase.orderId ?: "Unknown Order ID",
                            "Purchase successful for ${purchase.products.joinToString()}"
                        )
                        // If it's a consumable, consume it
                        val productDetails = _productDetailsFlow.value[purchase.products.firstOrNull()]?.originalProductDetails
                        if (productDetails?.productType == BillingClient.ProductType.INAPP && productDetails.oneTimePurchaseOfferDetails != null) {
                            consumePurchase(purchase)
                        }
                    } else {
                        // Verification failed, do not grant entitlement
                        _purchaseResultFlow.value = PaymentResult.Failure(
                            -1, // Custom error code
                            "Purchase verification failed on backend for ${purchase.orderId}"
                        )
                    }
                } else if (purchase.purchaseState == Purchase.PurchaseState.PENDING) {
                    _purchaseResultFlow.value = PaymentResult.Pending
                }
            }
            _purchasesFlow.value = validPurchases
        }
    }

    private suspend fun acknowledgePurchase(purchase: Purchase) {
        val acknowledgePurchaseParams = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        val billingResult = withContext(Dispatchers.IO) {
            billingClient.acknowledgePurchase(acknowledgePurchaseParams)
        }
        if (billingResult.responseCode != BillingClient.BillingResponseCode.OK) {
            // Log this error, as acknowledgment is critical
            _purchaseResultFlow.value = PaymentResult.Failure(
                billingResult.responseCode,
                "Failed to acknowledge purchase: ${billingResult.debugMessage}"
            )
        }
        // After acknowledgment, you might want to requery purchases to update the UI
        queryPurchases()
    }

    private suspend fun consumePurchase(purchase: Purchase) {
        val consumeParams = ConsumeParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        val consumeResult = withContext(Dispatchers.IO) {
            billingClient.consumePurchase(consumeParams)
        }

        if (consumeResult.billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
            // Consumption successful, item can be purchased again
            _purchaseResultFlow.value = PaymentResult.Success(
                purchase.orderId ?: "Unknown Order ID",
                "Item consumed: ${purchase.products.joinToString()}"
            )
        } else {
            _purchaseResultFlow.value = PaymentResult.Failure(
                consumeResult.billingResult.responseCode,
                "Failed to consume purchase: ${consumeResult.billingResult.debugMessage}"
            )
        }
        queryPurchases() // Refresh list after consumption
    }

    private fun queryPurchases() {
        if (!billingClient.isReady) {
            _purchaseResultFlow.value = PaymentResult.BillingUnavailable("Billing client not ready to query purchases.")
            return
        }

        val inAppParams = QueryPurchasesParams.newBuilder()
            .setProductType(BillingClient.ProductType.INAPP)
            .build()

        val subsParams = QueryPurchasesParams.newBuilder()
            .setProductType(BillingClient.ProductType.SUBS)
            .build()

        val listener = PurchasesResponseListener { billingResult, purchases ->
            if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                handlePurchases(purchases)
            } else {
                _purchaseResultFlow.value = PaymentResult.Failure(
                    billingResult.responseCode,
                    "Failed to query purchases: ${billingResult.debugMessage}"
                )
            }
        }

        // Query both in-app and subscriptions
        billingClient.queryPurchasesAsync(inAppParams, listener)
        billingClient.queryPurchasesAsync(subsParams, listener)
    }

    private suspend fun queryProductDetails() {
        if (!billingClient.isReady) {
            _purchaseResultFlow.value = PaymentResult.BillingUnavailable("Billing client not ready to query products.")
            return
        }

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        val (billingResult, productDetailsList) = withContext(Dispatchers.IO) {
            billingClient.queryProductDetails(params)
        }

        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && productDetailsList != null) {
            val mappedProducts = productDetailsList.associate { productDetails ->
                val price = productDetails.oneTimePurchaseOfferDetails?.formattedPrice
                    ?: productDetails.subscriptionOfferDetails?.firstOrNull()?.pricingPhases?.pricingPhaseList?.firstOrNull()?.formattedPrice
                    ?: "N/A"
                val description = productDetails.description.takeIf { it.isNotEmpty() } ?: "No description"

                productDetails.productId to ProductInfo(
                    productId = productDetails.productId,
                    type = productDetails.productType,
                    title = productDetails.title,
                    description = description,
                    price = price,
                    originalProductDetails = productDetails
                )
            }
            _productDetailsFlow.value = mappedProducts
        } else {
            _purchaseResultFlow.value = PaymentResult.Failure(
                billingResult.responseCode,
                "Failed to query product details: ${billingResult.debugMessage}"
            )
        }
    }

    /**
     * Launches the Google Play Billing purchase flow for a given product.
     * @param activity The activity context required to launch the billing flow.
     * @param productInfo The ProductInfo object representing the item to purchase.
     */
    fun launchPurchaseFlow(activity: Activity, productInfo: ProductInfo) {
        if (!billingClient.isReady) {
            _purchaseResultFlow.value = PaymentResult.BillingUnavailable("Billing client not ready.")
            connectToGooglePlay() // Attempt to reconnect
            return
        }

        val productDetails = productInfo.originalProductDetails
        val offerToken = if (productDetails.productType == BillingClient.ProductType.SUBS) {
            // For subscriptions, choose the appropriate offer.
            // This example takes the first available base plan + offer.
            productDetails.subscriptionOfferDetails?.firstOrNull()?.offerToken
        } else {
            productDetails.oneTimePurchaseOfferDetails?.offerToken
        }

        if (offerToken == null) {
            _purchaseResultFlow.value = PaymentResult.Failure(
                -1,
                "No valid offer token found for product: ${productInfo.productId}"
            )
            return
        }

        val productDetailsParams = BillingFlowParams.ProductDetailsParams.newBuilder()
            .setProductDetails(productDetails)
            .setOfferToken(offerToken)
            .build()

        val billingFlowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(listOf(productDetailsParams))
            .build()

        billingClient.launchBillingFlow(activity, billingFlowParams)
    }

    fun endConnection() {
        if (billingClient.isReady) {
            billingClient.endConnection()
        }
    }
}

// --- Main Payment Module ---

class PaymentModule(
    private val context: Context,
    private val externalPaymentProcessor: ExternalPaymentProcessor
) {
    private val coroutineScope = CoroutineScope(Dispatchers.Default)

    val googlePlayBillingManager = GooglePlayBillingManager(context, coroutineScope)

    // Expose flows from billing manager
    val googlePlayConnectionState: StateFlow<Int> = googlePlayBillingManager.connectionState
    val inAppProducts: StateFlow<Map<String, ProductInfo>> = googlePlayBillingManager.productDetailsFlow
    val currentPurchases: StateFlow<List<Purchase>> = googlePlayBillingManager.purchasesFlow
    val googlePlayPurchaseResult: StateFlow<PaymentResult?> = googlePlayBillingManager.purchaseResultFlow

    private val _walletTransactionResult = MutableStateFlow<PaymentResult?>(null)
    val walletTransactionResult: StateFlow<PaymentResult?> = _walletTransactionResult.asStateFlow()

    private val _directPaymentResult = MutableStateFlow<PaymentResult?>(null)
    val directPaymentResult: StateFlow<PaymentResult?> = _directPaymentResult.asStateFlow()

    fun launchGooglePlayPurchase(activity: Activity, productInfo: ProductInfo) {
        googlePlayBillingManager.launchPurchaseFlow(activity, productInfo)
    }

    fun processWalletTopUpWithExternalPayment(transaction: WalletTransaction) {
        coroutineScope.launch {
            _walletTransactionResult.value = externalPaymentProcessor.processWalletTopUp(transaction)
        }
    }

    fun processDirectPaymentWithExternalMethod(
        amount: Double,
        currency: String,
        description: String,
        paymentMethodToken: String
    ) {
        coroutineScope.launch {
            _directPaymentResult.value = externalPaymentProcessor.processDirectPayment(
                amount,
                currency,
                description,
                paymentMethodToken
            )
        }
    }

    fun resetWalletTransactionResult() {
        _walletTransactionResult.value = null
    }

    fun resetDirectPaymentResult() {
        _directPaymentResult.value = null
    }

    fun resetGooglePlayPurchaseResult() {
        googlePlayBillingManager._purchaseResultFlow.value = null
    }

    fun onDestroy() {
        googlePlayBillingManager.endConnection()
        coroutineScope.cancel() // Cancel any ongoing coroutines
    }
}

